export class AlertsCenterComponent {
  constructor(aircraftService, pageService) {
    this.aircraftService = aircraftService;
    this.pageService = pageService;
    this.alerts$ = this.aircraftService.alerts$;
    this.activeAlertsCount$ = this.aircraftService.activeAlerts$;
    this.activeFilter = 'all';
    this.filters = [{
      label: 'Tous',
      value: 'all'
    }, {
      label: 'Critiques',
      value: 'critical'
    }, {
      label: 'Avertissements',
      value: 'warning'
    }];
  }
  ngOnInit() {
    this.pageService.setPage('alerts', 'Centre d\'alertes', 'Anomalies et incidents en cours');
  }
  setFilter(filter) {
    this.activeFilter = filter;
  }
  filteredAlerts(alerts) {
    if (this.activeFilter === 'all') {
      return alerts;
    }
    return alerts.filter(alert => {
      const level = this.getAlertLevel(alert);
      return level === this.activeFilter;
    });
  }
  getAlertLevel(alert) {
    return alert.speed > 800 ? 'critical' : 'warning';
  }
  getAlertIcon(level) {
    return level === 'critical' ? '🚨' : '⚠️';
  }
  dismissAlert(alertId) {
    console.log('Dismiss alert:', alertId);
  }
}
